/**
 * Ordered list of the languages CodeExplain claims to support.
 * Python and JavaScript are the two mandated by the spec; the rest are
 * enabled because the model handles them without special-casing.
 */

export interface LanguageOption {
  key: string;    // canonical identifier the backend receives
  label: string;  // shown in the pill dropdown
}

export const LANGUAGES: LanguageOption[] = [
  { key: 'python', label: 'Python' },
  { key: 'javascript', label: 'JavaScript' },
  { key: 'typescript', label: 'TypeScript' },
  { key: 'java', label: 'Java' },
  { key: 'c', label: 'C' },
  { key: 'cpp', label: 'C++' },
  { key: 'go', label: 'Go' },
];

/** Very lightweight heuristic to pre-fill the language pill from pasted code. */
export function detectLanguage(code: string): string | null {
  const c = code.trim();
  if (!c) return null;

  if (/^\s*def\s+\w+\s*\(|^\s*import\s+\w+|print\(/m.test(c)) return 'python';
  if (/\b(?:const|let|var)\b|=>|console\.log/.test(c)) return 'javascript';
  if (/^\s*(?:public|private)\s+(?:static\s+)?(?:void|class)\b/m.test(c)) return 'java';
  if (/#include\s*<[\w./]+>/.test(c)) return c.includes('std::') ? 'cpp' : 'c';
  if (/^\s*package\s+\w+|:=|func\s+\w+\s*\(/m.test(c)) return 'go';

  return null;
}
